```php
<?php
// Écrire dans un fichier (crée ou écrase)
file_put_contents("/tmp/test.txt", "Ligne 1\nLigne 2\n");

// Lire tout le fichier
$contenu = file_get_contents("/tmp/test.txt");
echo $contenu;

// Lire ligne par ligne
$lignes = file("/tmp/test.txt", FILE_IGNORE_NEW_LINES);
foreach ($lignes as $i => $ligne) {
    echo "[$i] $ligne\n";
}

// Vérifier si un fichier existe
if (file_exists("/tmp/test.txt")) {
    echo "Le fichier existe\n";
    echo "Taille : " . filesize("/tmp/test.txt") . " octets\n";
}

// Ajouter du contenu (sans écraser)
file_put_contents("/tmp/test.txt", "Ligne 3\n", FILE_APPEND);

// Supprimer
unlink("/tmp/test.txt");

// Créer un dossier
mkdir("/tmp/mon_dossier", 0755);
?>
```

```php
<?php
// Encoder un tableau PHP en JSON
$donnees = [
    "nom"    => "Alice",
    "age"    => 28,
    "langages" => ["PHP", "Python"]
];

$json = json_encode($donnees, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE);
echo $json . "\n";
// {
//   "nom": "Alice",
//   "age": 28,
//   "langages": ["PHP", "Python"]
// }

// Décoder un JSON en tableau PHP
$texte_json = '{"ville":"Paris","code":75}';
$ville = json_decode($texte_json, true);  // true = tableau, false = objet
echo $ville["ville"] . "\n";   // Paris
echo $ville["code"] . "\n";    // 75

// Sauvegarder dans un fichier JSON
file_put_contents("/tmp/data.json", json_encode($donnees, JSON_PRETTY_PRINT));

// Lire depuis un fichier JSON
$config = json_decode(file_get_contents("/tmp/data.json"), true);
echo $config["nom"] . "\n";    // Alice
?>
```

`JSON_PRETTY_PRINT` = formatage indenté, `JSON_UNESCAPED_UNICODE` = accents non échappés.
